import{_ as a,o as r,c as e,a2 as d}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"散裝航運獲利模型","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-4_散裝航運獲利模型.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-4_散裝航運獲利模型.md"}'),o={name:"Deep32Q知識庫/產業洞察/航運產業/05_航運週期與景氣判斷/05-4_散裝航運獲利模型.md"};function s(n,t,i,l,h,g){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="散裝航運獲利模型" tabindex="-1">散裝航運獲利模型 <a class="header-anchor" href="#散裝航運獲利模型" aria-label="Permalink to &quot;散裝航運獲利模型&quot;">​</a></h1><h2 id="📊-tce-time-charter-equivalent-計算方法" tabindex="-1">📊 TCE（Time Charter Equivalent）計算方法 <a class="header-anchor" href="#📊-tce-time-charter-equivalent-計算方法" aria-label="Permalink to &quot;📊 TCE（Time Charter Equivalent）計算方法&quot;">​</a></h2><p>TCE 是散裝航運業衡量船舶每日營收的核心指標，用於跨航次、船型、租約方式比較獲利能力。</p><h3 id="計算公式" tabindex="-1">計算公式 <a class="header-anchor" href="#計算公式" aria-label="Permalink to &quot;計算公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TCE = (總運費收入 – 航次成本) ÷ 航次天數</span></span></code></pre></div><h3 id="成本組成" tabindex="-1">成本組成 <a class="header-anchor" href="#成本組成" aria-label="Permalink to &quot;成本組成&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>佔比</th><th>說明</th></tr></thead><tbody><tr><td><strong>燃油成本</strong></td><td>30–50%</td><td>最大變數成本，受油價、航線、船齡影響</td></tr><tr><td><strong>港口費用</strong></td><td>~21%</td><td>裝卸港費、引水費、繫泊費等</td></tr><tr><td><strong>運河通行費</strong></td><td>可觀</td><td>蘇伊士 $30–70 萬、巴拿馬 $20–50 萬</td></tr><tr><td><strong>經紀佣金</strong></td><td>1.25%</td><td>成交額的 1.25%，部分航線可議價</td></tr><tr><td><strong>其他</strong></td><td>剩餘</td><td>保險、通訊、雜費等</td></tr></tbody></table><h3 id="損益平衡日租金" tabindex="-1">損益平衡日租金 <a class="header-anchor" href="#損益平衡日租金" aria-label="Permalink to &quot;損益平衡日租金&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>損益平衡 TCE = 每日營運成本 + 每日資本成本</span></span></code></pre></div><hr><h2 id="📈-2026-年各船型-tce-水準" tabindex="-1">📈 2026 年各船型 TCE 水準 <a class="header-anchor" href="#📈-2026-年各船型-tce-水準" aria-label="Permalink to &quot;📈 2026 年各船型 TCE 水準&quot;">​</a></h2><h3 id="capesize-好望角型-18-萬-dwt" tabindex="-1">Capesize（好望角型，18 萬 DWT） <a class="header-anchor" href="#capesize-好望角型-18-萬-dwt" aria-label="Permalink to &quot;Capesize（好望角型，18 萬 DWT）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>備註</th></tr></thead><tbody><tr><td><strong>即期航次 TCE</strong></td><td>~$28,000/天（2 月均價）</td><td>創近年高點</td></tr><tr><td><strong>1 年期期租</strong></td><td>~$30,000–$32,000/天（3 月）</td><td>大西洋/太平洋均價</td></tr><tr><td><strong>每日營運成本</strong></td><td>~$6,094/天（2026 Q1 均價）</td><td>含 crew、保險、維護</td></tr><tr><td><strong>損益平衡 TCE</strong></td><td>~$8,500–$10,000/天</td><td>含資本成本後約 $12,000–$15,000</td></tr><tr><td><strong>淨利空間</strong></td><td>~$15,000–$20,000/天</td><td>當前市場處於高獲利區間</td></tr></tbody></table><h3 id="panamax-巴拿馬型-7-萬-dwt" tabindex="-1">Panamax（巴拿馬型，7 萬 DWT） <a class="header-anchor" href="#panamax-巴拿馬型-7-萬-dwt" aria-label="Permalink to &quot;Panamax（巴拿馬型，7 萬 DWT）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>備註</th></tr></thead><tbody><tr><td><strong>即期航次 TCE</strong></td><td>~$16,000/天（2 月均價）</td><td>Q1 平均 $15,252/天</td></tr><tr><td><strong>1 年期期租</strong></td><td>~$16,250–$16,500/天（3 月）</td><td>大西洋/太平洋均價</td></tr><tr><td><strong>每日營運成本</strong></td><td>~$5,500–$6,500/天</td><td>較 Capesize 略低</td></tr><tr><td><strong>損益平衡 TCE</strong></td><td>~$8,000–$10,000/天</td><td>含資本成本後約 $12,000–$14,000</td></tr><tr><td><strong>淨利空間</strong></td><td>~$5,000–$8,000/天</td><td>利潤空間較窄，受新船交付壓力影響</td></tr></tbody></table><h3 id="supramax-超靈便型-5-5-萬-dwt" tabindex="-1">Supramax（超靈便型，5.5 萬 DWT） <a class="header-anchor" href="#supramax-超靈便型-5-5-萬-dwt" aria-label="Permalink to &quot;Supramax（超靈便型，5.5 萬 DWT）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th><th>備註</th></tr></thead><tbody><tr><td><strong>即期航次 TCE</strong></td><td>~$12,000–$14,000/天（Q1 均價）</td><td>農產品貿易支撐</td></tr><tr><td><strong>每日營運成本</strong></td><td>~$5,000–$6,000/天</td><td>船型較小，營運成本最低</td></tr><tr><td><strong>損益平衡 TCE</strong></td><td>~$7,000–$9,000/天</td><td>含資本成本後約 $10,000–$12,000</td></tr></tbody></table><hr><h2 id="🔍-影響散裝獲利的關鍵變數" tabindex="-1">🔍 影響散裝獲利的關鍵變數 <a class="header-anchor" href="#🔍-影響散裝獲利的關鍵變數" aria-label="Permalink to &quot;🔍 影響散裝獲利的關鍵變數&quot;">​</a></h2><h3 id="利多因素-2026" tabindex="-1">利多因素（2026） <a class="header-anchor" href="#利多因素-2026" aria-label="Permalink to &quot;利多因素（2026）&quot;">​</a></h3><ol><li><strong>Simandou 鐵礦項目</strong>：幾內亞大型鐵礦開採，長距離運輸至中國推升 Capesize 需求</li><li><strong>澳洲/巴西出口強勁</strong>：鐵礦砂、煤炭出口量創高</li><li><strong>船隊增長放緩</strong>：Capesize 淨增長僅 2.2%，連續五年低於平均</li><li><strong>航程拉長</strong>：幾內亞→中國航線 + 港口等待時間增加有效需求</li></ol><h3 id="風險因素" tabindex="-1">風險因素 <a class="header-anchor" href="#風險因素" aria-label="Permalink to &quot;風險因素&quot;">​</a></h3><ol><li><strong>Panamax 新船交付</strong>：2026 年預計交付 15–16 百萬 DWT（近年約 10 百萬），供應壓力增大</li><li><strong>中國房地產放緩</strong>：鐵礦進口增速可能放緩</li><li><strong>煤炭貿易萎縮</strong>：Panamax 主要貨物之一，受能源轉型影響</li><li><strong>EEXI/CII 降速</strong>：老船需降速 1–2 節，影響營運效率</li></ol><hr><h2 id="📊-典型航次獲利範例-capesize-2026-q1" tabindex="-1">📊 典型航次獲利範例（Capesize，2026 Q1） <a class="header-anchor" href="#📊-典型航次獲利範例-capesize-2026-q1" aria-label="Permalink to &quot;📊 典型航次獲利範例（Capesize，2026 Q1）&quot;">​</a></h2><h3 id="巴西→中國鐵礦航次" tabindex="-1">巴西→中國鐵礦航次 <a class="header-anchor" href="#巴西→中國鐵礦航次" aria-label="Permalink to &quot;巴西→中國鐵礦航次&quot;">​</a></h3><ul><li><strong>運費收入</strong>：約 $45–50 萬/航次（按當前即期費率）</li><li><strong>燃油成本</strong>：約 $18–22 萬（VLSFO ~$963/MT，耗油約 150–200 MT）</li><li><strong>港口費用</strong>：約 $8–12 萬（巴西裝港 + 中國卸港）</li><li><strong>運河費</strong>：約 $0（繞好望角，不經巴拿馬）</li><li><strong>航次天數</strong>：約 35–40 天（巴西→中國）</li><li><strong>TCE</strong>：約 $25,000–$30,000/天</li><li><strong>淨利</strong>：約 $15,000–$20,000/天（扣除營運成本後）</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>SP Global Platts (2026): Dry Freight TCE 計算方法與 FAQ</li><li>Breakwave Advisors (2026-03-16): 散裝市場 2026 年展望</li><li>Seeking Alpha (2026-05): Pangaea Logistics Q1 2026 TCE $18,808/天</li><li>GlobeNewsWire (2026-05-13): Costamare Bulk Q1 2026 營收報告</li><li>HandyBulk (n.d.): TCE 計算公式與範例</li></ol>',30)])])}const p=a(o,[["render",s]]);export{b as __pageData,p as default};
